class Solution:
    def calculate(self, s: str) -> int:
        s = s.replace(' ', '')
        n, num, last, result, op = len(s), 0, 0, 0, '+'
        for i, c in enumerate(s):
            if c.isdigit():
                num = num * 10 + int(c)
            if not c.isdigit() or i == n - 1:
                if op == '+':
                    result += last
                    last = num
                elif op == '-':
                    result += last
                    last = -num
                elif op == '*':
                    last *= num
                elif op == '/':
                    last = int(last / num)
                op = c
                num = 0
        return result + last

